SELECT [qSoloVend-PerGriglieAgenti].GeoZone2Description, [qSoloVend-PerGriglieAgenti].GeoZone1Description, [qSoloVend-PerGriglieAgenti].[Sell-to Customer No_], [qSoloVend-PerGriglieAgenti].[Sell-to Name], [qSoloVend-PerGriglieAgenti].City, [qSoloVend-PerGriglieAgenti].[Current Risk], [qSoloVend-PerGriglieAgenti].[risk rating], [qSoloVend-PerGriglieAgenti].[trademark code], [qSoloVend-PerGriglieAgenti].[season code], [qSoloVend-PerGriglieAgenti].Salesperson, [qSoloVend-PerGriglieAgenti].[Purchase Group], [qSoloVend-PerGriglieAgenti].[Payment Method Code], [qSoloVend-PerGriglieAgenti].[Payment Terms Code], [qSoloVend-PerGriglieAgenti].ScontoFattura, [qSoloVend-PerGriglieAgenti].ContoVendita, [qSoloVend-PerGriglieAgenti].PercentualeDirittoAlReso, [qSoloVend-PerGriglieAgenti].[Requested Delivery Date], Sum([qSoloVend-PerGriglieAgenti].PairsSold) AS PairsSold, Sum(Format$([ValueSold],"Currency")) AS ValueSold_, Sum(Format$([ValueSoldVAT],"Standard")) AS ValueSoldVAT_, "" AS [NOTE], [qSoloVend-PerGriglieAgenti].[Blocked for Assignments], [qSoloVend-PerGriglieAgenti].[Reason Block Code]
FROM [qSoloVend-PerGriglieAgenti]
GROUP BY [qSoloVend-PerGriglieAgenti].GeoZone2Description, [qSoloVend-PerGriglieAgenti].GeoZone1Description, [qSoloVend-PerGriglieAgenti].[Sell-to Customer No_], [qSoloVend-PerGriglieAgenti].[Sell-to Name], [qSoloVend-PerGriglieAgenti].City, [qSoloVend-PerGriglieAgenti].[Current Risk], [qSoloVend-PerGriglieAgenti].[risk rating], [qSoloVend-PerGriglieAgenti].[trademark code], [qSoloVend-PerGriglieAgenti].[season code], [qSoloVend-PerGriglieAgenti].Salesperson, [qSoloVend-PerGriglieAgenti].[Purchase Group], [qSoloVend-PerGriglieAgenti].[Payment Method Code], [qSoloVend-PerGriglieAgenti].[Payment Terms Code], [qSoloVend-PerGriglieAgenti].ScontoFattura, [qSoloVend-PerGriglieAgenti].ContoVendita, [qSoloVend-PerGriglieAgenti].PercentualeDirittoAlReso, [qSoloVend-PerGriglieAgenti].[Requested Delivery Date], "", [qSoloVend-PerGriglieAgenti].[Blocked for Assignments], [qSoloVend-PerGriglieAgenti].[Reason Block Code], [qSoloVend-PerGriglieAgenti].GeoZone2Description, [qSoloVend-PerGriglieAgenti].[Geographical Zone]
HAVING ((([qSoloVend-PerGriglieAgenti].[season code])=[forms]![principale]![creditofiltrostagione2]) AND (([qSoloVend-PerGriglieAgenti].[Blocked for Assignments])=1))
ORDER BY [qSoloVend-PerGriglieAgenti].GeoZone2Description, [qSoloVend-PerGriglieAgenti].[Geographical Zone], [qSoloVend-PerGriglieAgenti].[Sell-to Name], [qSoloVend-PerGriglieAgenti].[trademark code];

